import React, { useEffect, useState } from 'react';
import IndiaMap from './IndiaMap';
import Layout from './Layout';
import API from '../api/api';
import { FaBook, FaGlobeAsia, FaChartBar, FaLightbulb, FaTimes } from 'react-icons/fa';
import { Link } from 'react-router-dom';
import './Dashboard.css';

const stateAndUTData = {
  states: [
    'Andhra Pradesh', 'Arunachal Pradesh', 'Assam', 'Bihar', 'Chhattisgarh',
    'Goa', 'Gujarat', 'Haryana', 'Himachal Pradesh', 'Jharkhand', 'Karnataka',
    'Kerala', 'Madhya Pradesh', 'Maharashtra', 'Manipur', 'Meghalaya',
    'Mizoram', 'Nagaland', 'Odisha', 'Punjab', 'Rajasthan', 'Sikkim',
    'Tamil Nadu', 'Telangana', 'Tripura', 'Uttar Pradesh', 'Uttarakhand',
    'West Bengal'
  ],
  unionTerritories: [
    'Andaman and Nicobar Islands', 'Chandigarh',
    'Dadra and Nagar Haveli and Daman and Diu',
    'Delhi', 'Jammu and Kashmir', 'Ladakh', 'Lakshadweep', 'Puducherry'
  ]
};

const travelTips = [
  'Click on any state to mark it as visited - the map will highlight it in green.',
  'Use the Travel Journal to track specific destinations within each state.',
  'Check the Statistics page to see your milestones and achievements.',
  'Plan your next trip using the Travel Planner to stay organized.',
  'Explore the World Map to track countries you have visited globally.',
  'The more states you visit, the more milestone badges you unlock!',
  'Track union territories separately - there are 8 to explore in India.',
  'Your travel data is synced to the cloud and accessible from anywhere.',
];

function normalizeWords(name) {
  return name.toLowerCase().replace(/[^a-z0-9 ]/g, '').split(' ').filter(Boolean);
}

function fuzzyIncludes(list, name) {
  const nameWords = normalizeWords(name);
  return list.some(item => {
    const itemWords = normalizeWords(item);
    return nameWords.every(w => itemWords.includes(w)) || itemWords.every(w => nameWords.includes(w));
  });
}

export default function Dashboard() {
  const [selectedLocations, setSelectedLocations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showWelcome, setShowWelcome] = useState(false);
  const [user, setUser] = useState({ name: 'Explorer' });

  useEffect(() => {
    try {
      const stored = JSON.parse(localStorage.getItem('user'));
      if (stored?.name) setUser(stored);
    } catch {}
    setShowWelcome(!localStorage.getItem('dashboard-welcome-dismissed'));
  }, []);

  useEffect(() => {
    async function fetchSelected() {
      try {
        const res = await API.get('/api/user/selected');
        setSelectedLocations(res.data.selectedLocations || []);
      } catch {
        setSelectedLocations([]);
      } finally {
        setLoading(false);
      }
    }
    fetchSelected();
  }, []);

  useEffect(() => {
    if (selectedLocations.length > 0) {
      API.post('/api/user/selected', { selectedLocations }).catch(() => {});
    }
  }, [selectedLocations]);

  const dismissWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('dashboard-welcome-dismissed', 'true');
  };

  // Stats
  const indiaLocations = selectedLocations.filter(loc => !loc.type || loc.type !== 'country');
  const visitedStatesCount = indiaLocations.filter(loc => fuzzyIncludes(stateAndUTData.states, loc.name || '')).length;
  const visitedUTsCount = stateAndUTData.unionTerritories.filter(ut => {
    if (ut === 'Dadra and Nagar Haveli and Daman and Diu') {
      return indiaLocations.some(sel =>
        fuzzyIncludes(['Dadra and Nagar Haveli and Daman and Diu', 'Daman and Diu', 'Dadra and Nagar Haveli'], sel.name || '')
      );
    }
    return indiaLocations.some(sel => fuzzyIncludes([ut], sel.name || ''));
  }).length;

  const totalStates = stateAndUTData.states.length;
  const totalUTs = stateAndUTData.unionTerritories.length;
  const totalPlaces = totalStates + totalUTs;
  const totalVisited = visitedStatesCount + visitedUTsCount;
  const overallPercent = totalPlaces > 0 ? Math.round((totalVisited / totalPlaces) * 100) : 0;

  const todayTip = travelTips[new Date().getDate() % travelTips.length];

  const statCards = [
    { label: 'States Visited', count: visitedStatesCount, total: totalStates, color: 'var(--accent-500)', bg: 'var(--accent-50)' },
    { label: 'UTs Visited', count: visitedUTsCount, total: totalUTs, color: 'var(--primary-500)', bg: 'var(--primary-50)' },
    { label: 'States Pending', count: totalStates - visitedStatesCount, total: totalStates, color: 'var(--amber-500)', bg: '#fffbeb' },
    { label: 'UTs Pending', count: totalUTs - visitedUTsCount, total: totalUTs, color: 'var(--rose-500)', bg: '#fff1f2' },
  ];

  return (
    <Layout>
      <div className="dashboard-page">
        {/* Header */}
        <div className="page-header">
          <div>
            <h1 className="page-title">India Dashboard</h1>
            <p className="page-subtitle">Your glimpse across states and union territories</p>
          </div>
          <div className="header-progress">
            <div className="progress-ring">
              <svg viewBox="0 0 36 36">
                <path className="progress-ring-bg" d="M18 2.0845a 15.9155 15.9155 0 0 1 0 31.831a 15.9155 15.9155 0 0 1 0 -31.831" />
                <path className="progress-ring-fill" strokeDasharray={`${overallPercent}, 100`} d="M18 2.0845a 15.9155 15.9155 0 0 1 0 31.831a 15.9155 15.9155 0 0 1 0 -31.831" />
              </svg>
              <span className="progress-ring-text">{overallPercent}%</span>
            </div>
            <div className="progress-info">
              <span className="progress-label">Overall Progress</span>
              <span className="progress-detail">{totalVisited} of {totalPlaces} explored</span>
            </div>
          </div>
        </div>

        {/* Welcome Banner */}
        {showWelcome && (
          <div className="welcome-banner">
            <button className="welcome-dismiss" onClick={dismissWelcome} aria-label="Dismiss"><FaTimes /></button>
            <h2>Welcome, {user.name.split(' ')[0]}!</h2>
            <p>Start exploring India by clicking states on the map below. Track destinations, plan trips, and unlock milestones.</p>
            <div className="welcome-actions">
              <Link to="/journal" className="welcome-link"><FaBook /> Journal</Link>
              <Link to="/worldmap" className="welcome-link"><FaGlobeAsia /> World Map</Link>
              <Link to="/statistics" className="welcome-link"><FaChartBar /> Statistics</Link>
            </div>
          </div>
        )}

        {/* Travel Tip */}
        <div className="travel-tip">
          <FaLightbulb className="tip-icon" />
          <span>{todayTip}</span>
        </div>

        {/* Stats Cards */}
        {loading ? (
          <div className="stats-grid">
            {[0, 1, 2, 3].map(i => (
              <div key={i} className="stat-card skeleton-card">
                <div className="skeleton skeleton-icon" />
                <div className="skeleton-lines">
                  <div className="skeleton skeleton-line-sm" />
                  <div className="skeleton skeleton-line-xs" />
                  <div className="skeleton skeleton-bar" />
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="stats-grid">
            {statCards.map((card, i) => (
              <div key={i} className="stat-card" style={{ '--i': i, '--card-color': card.color, '--card-bg': card.bg }}>
                <div className="stat-card-icon" style={{ background: card.bg, color: card.color }}>
                  <span className="stat-card-number">{card.count}</span>
                </div>
                <div className="stat-card-content">
                  <span className="stat-card-label">{card.label}</span>
                  <span className="stat-card-fraction">{card.count} / {card.total}</span>
                  <div className="stat-card-bar">
                    <div className="stat-card-bar-fill" style={{ width: `${card.total > 0 ? (card.count / card.total) * 100 : 0}%`, background: card.color }} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Map */}
        <div className="map-card">
          <div className="map-card-header">
            <h2>Interactive India Map</h2>
            <span className="map-hint">Click a state or UT to mark as visited</span>
          </div>
          <div className="map-card-body">
            {loading ? (
              <div className="skeleton" style={{ width: '80%', height: '400px', margin: '2rem auto' }} />
            ) : (
              <IndiaMap selectedLocations={indiaLocations} setSelectedLocations={setSelectedLocations} />
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
}
